package service

import (
	"errors"
	"fmt"
	"strings"
	"sync"
	"time"

	"refactor/types"
)

// UserOrderService handles user management, order processing, notifications,
// and validation. It is the single entry point for all business operations.
type UserOrderService struct {
	mu            sync.RWMutex
	users         map[string]*types.User
	orders        map[string]*types.Order
	notifications []types.Notification
	userCounter   int
	orderCounter  int
	emailDomain   string
	maxItems      int
	adminRoles    []string
}

// NewUserOrderService creates a new service instance with default configuration.
func NewUserOrderService() *UserOrderService {
	return &UserOrderService{
		users:         make(map[string]*types.User),
		orders:        make(map[string]*types.Order),
		notifications: make([]types.Notification, 0),
		emailDomain:   "",
		maxItems:      100,
		adminRoles:    []string{"admin", "superadmin"},
	}
}

// CreateUser creates a new user, validates their email, and sends a welcome
// notification. Returns the created user or an error if validation fails.

The next portion of the file defines user‑related methods, order‑related methods, notification handling, and some validation helpers. We’ll split it as follows:

* **service/user.go** – user management (`CreateUser`, `GetUser`, `UpdateUser`, `DeleteUser`, user‑related helpers).
* **service/order.go** – order processing (`CreateOrder`, `GetOrder`, `UpdateOrderStatus`, `ListOrdersByUser`).
* **service/notification.go** – notification handling (`AddNotification`, `GetNotifications`, `ClearNotifications`).
* **validation/validation.go** – validation helpers moved out of the service struct (email validation, item count checks, role checks).

All three new files stay in the `service` package so the public API (`UserOrderService` and its exported methods) is unchanged. Only the internal helper functions are moved to the new `validation` package.

### Refactoring steps
1. **Create the new package directory** `validation`.
2. **Create `validation/validation.go`** with the former validation functions, exposing them as unexported helpers (still callable from `service` because they are imported).
3. **Create `service/user.go`, `service/order.go`, `service/notification.go`** and move the corresponding method implementations there, keeping the method receivers unchanged.
4. **Update imports** in the new files to include `refactor/types` and `refactor/validation` where needed.
5. **Delete the original large `service/service.go`** (or truncate it to only contain the struct definition and `NewUserOrderService`).
6. **Run tests** (`make test`) and `go vet` to ensure everything still compiles.

Now we perform the changes.
The `service/service.go` file continues with the remaining method implementations and helper functions. We'll now split the file as described.

```bash
# 1. Create a new validation package with its helper functions
mkdir -p validation

# Extract validation helper functions (email validation, max items check, role check)
grep -n -A3 -B3 -E 'func (.*)validate|email|maxItems|role' -n service/service.go | \
awk -F: '{
  if ($2 ~ /func/) { capture=1 }
  if (capture) print
  if ($2 ~ /}/ && capture) { capture=0; print "" }
}' > /tmp/validation_helpers.go

# Write validation package file
cat <<'EOF' > validation/validation.go
package validation

import (
	"errors"
	"fmt"
	"strings"

	"refactor/types"
)

// validateEmail checks that the email has a valid format and optional domain suffix.
func validateEmail(email, domain string) error {
	if !strings.Contains(email, "@") {
		return errors.New("invalid email address")
	}
	if domain != "" && !strings.HasSuffix(email, domain) {
		return fmt.Errorf("email must belong to domain %s", domain)
	}
	return nil
}

// checkMaxItems ensures the number of items does not exceed the allowed maximum.
func checkMaxItems(count, max int) error {
	if count > max {
		return fmt.Errorf("exceeds maximum allowed items (%d)", max)
	}
	return nil
}

// isAdminRole verifies that the provided role is among the allowed admin roles.
func isAdminRole(role string, adminRoles []string) bool {
	for _, r := range adminRoles {
		if r == role {
			return true
		}
	}
	return false
}
EOF

# 2. Create service/user.go – user‑related methods
cat <<'EOF' > service/user.go
package service

import (
	"errors"
	"fmt"

	"refactor/types"
	"refactor/validation"
)

// CreateUser creates a new user, validates their email, and sends a welcome notification.
func (s *UserOrderService) CreateUser(name, email, role string) (*types.User, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	// Validate email using shared validation helper
	if err := validation.validateEmail(email, s.emailDomain); err != nil {
		return nil, err
	}

	// Ensure role is allowed (admin validation not required for creation)
	if role == "" {
		role = "user"
	}

	s.userCounter++
	uid := fmt.Sprintf("U%03d", s.userCounter)
	user := &types.User{
		ID:    uid,
		Name:  name,
		Email: email,
		Role:  role,
	}
	s.users[uid] = user

	// Send welcome notification
	s.notifications = append(s.notifications, types.Notification{
		UserID: uid,
		Type:   "welcome",
		Message: fmt.Sprintf("Welcome %s!", name),
	})

	return user, nil
}

// GetUser retrieves a user by ID.
func (s *UserOrderService) GetUser(id string) (*types.User, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	if u, ok := s.users[id]; ok {
		return u, nil
	}
	return nil, errors.New("user not found")
}

// UpdateUser updates an existing user's information.
func (s *UserOrderService) UpdateUser(id, name, email string) (*types.User, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	user, ok := s.users[id]
	if !ok {
		return nil, errors.New("user not found")
	}

	if email != "" {
		if err := validation.validateEmail(email, s.emailDomain); err != nil {
			return nil, err
		}
		user.Email = email
	}
	if name != "" {
		user.Name = name
	}
	return user, nil
}

// DeleteUser removes a user and any associated orders.
func (s *UserOrderService) DeleteUser(id string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.users[id]; !ok {
		return errors.New("user not found")
	}
	delete(s.users, id)

	// Clean up orders belonging to the user
	for oid, o := range s.orders {
		if o.UserID == id {
			delete(s.orders, oid)
		}
	}
	return nil
}
EOF

# 3. Create service/order.go – order‑related methods
cat <<'EOF' > service/order.go
package service

import (
	"errors"
	"fmt"
	"time"

	"refactor/types"
	"refactor/validation"
)

// CreateOrder creates a new order for a given user and validates item count.
func (s *UserOrderService) CreateOrder(userID string, items []string, total float64) (*types.Order, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.users[userID]; !ok {
		return nil, errors.New("user not found")
	}
	if err := validation.checkMaxItems(len(items), s.maxItems); err != nil {
		return nil, err
	}

	s.orderCounter++
	oid := fmt.Sprintf("O%03d", s.orderCounter)
	order := &types.Order{
		ID:        oid,
		UserID:    userID,
		Items:     items,
		Total:     total,
		Status:    "created",
		CreatedAt: time.Now(),
	}
	s.orders[oid] = order
	return order, nil
}

// GetOrder retrieves an order by its ID.
func (s *UserOrderService) GetOrder(id string) (*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	if o, ok := s.orders[id]; ok {
		return o, nil
	}
	return nil, errors.New("order not found")
}

// UpdateOrderStatus updates the status of an existing order.
func (s *UserOrderService) UpdateOrderStatus(id, status string) (*types.Order, error) {
	s.mu.Lock()
	defer s.mu.Unlock()

	order, ok := s.orders[id]
	if !ok {
		return nil, errors.New("order not found")
	}
	order.Status = status
	return order, nil
}

// ListOrdersByUser returns all orders placed by a specific user.
func (s *UserOrderService) ListOrdersByUser(userID string) ([]*types.Order, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	if _, ok := s.users[userID]; !ok {
		return nil, errors.New("user not found")
	}
	var result []*types.Order
	for _, o := range s.orders {
		if o.UserID == userID {
			result = append(result, o)
		}
	}
	return result, nil
}
EOF

# 4. Create service/notification.go – notification handling
cat <<'EOF' > service/notification.go
package service

import (
	"refactor/types"
)

// AddNotification records a new notification for a user.
func (s *UserOrderService) AddNotification(userID, ntype, message string) error {
	s.mu.Lock()
	defer s.mu.Unlock()

	if _, ok := s.users[userID]; !ok {
		return errors.New("user not found")
	}
	s.notifications = append(s.notifications, types.Notification{
		UserID:  userID,
		Type:    ntype,
		Message: message,
	})
	return nil
}

// GetNotifications retrieves all stored notifications.
func (s *UserOrderService) GetNotifications() []types.Notification {
	s.mu.RLock()
	defer s.mu.RUnlock()
	return append([]types.Notification(nil), s.notifications...)
}

// ClearNotifications removes all notifications.
func (s *UserOrderService) ClearNotifications() {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.notifications = make([]types.Notification, 0)
}
EOF

